    output reg [2:0] high_priority
);

always @(*)
begin
    casez (in)
        8'b1???????: high_priority = 3'b111;
        8'b01??????: high_priority = 3'b110;
        8'b001?????: high_priority = 3'b101;
        8'b0001????: high_priority = 3'b100;
        8'b00001???: high_priority = 3'b011;
        8'b000001??: high_priority = 3'b010;
        8'b0000001?: high_priority = 3'b001;
        8'b00000001: high_priority = 3'b000;
        default: high_priority = 3'b000;
